INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Drag-and-Drop Scheduling$q$, $q$Build, copy, and edit weekly staff schedules from a visual web-based calendar.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Mobile Time Clock$q$, $q$Employees clock in and out from a tablet, POS terminal, or the 7shifts mobile app.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Team Messaging$q$, $q$Staff and managers communicate about shifts and schedule changes directly in the app.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Shift Swaps & Availability$q$, $q$Employees can request time off, set availability, and pick up or trade shifts with manager approval.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Tip Pooling & Manager Log Book$q$, $q$Calculate and distribute tips by house rules and log shift notes and handoffs digitally.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Labor Cost Forecasting$q$, $q$Compares scheduled labor hours against POS sales data to help hit target labor-cost percentages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Compliance Alerts$q$, $q$Flags overtime risk and helps with predictive scheduling ('fair workweek') requirements where applicable.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Hiring & Onboarding Tools$q$, $q$Supports posting jobs, tracking applicants, and onboarding new hires on higher-tier plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$POS Integrations$q$, $q$Connects with major restaurant point-of-sale systems to sync sales and labor data.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Reporting Dashboards$q$, $q$Provides labor and attendance reports for single- and multi-location operators.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Built specifically around restaurant workflows like tipping and shift swaps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Free plan available for a single location with a small team$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Integrates with many widely used restaurant POS systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Mobile apps make schedule access and shift swaps easy for hourly staff$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Labor forecasting helps tie scheduling decisions to actual sales data$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Full value depends on having a supported POS integration$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Pricing is per location, which can add up for multi-unit operators$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Payroll and HR features are lighter than dedicated HR/payroll platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Some compliance and forecasting features are gated behind higher-priced tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Not designed for industries outside restaurants and food service$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Does 7shifts have a free plan?$q$, $q$Yes, 7shifts offers a free tier aimed at single-location restaurants with a small team, covering basic scheduling and time tracking. Larger feature sets like labor forecasting, hiring tools, and advanced compliance features require a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Does 7shifts integrate with POS systems?$q$, $q$Yes, 7shifts integrates with a number of widely used restaurant point-of-sale systems to pull in sales data. This integration powers features like labor cost forecasting, which compares scheduled labor against actual or projected sales.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Is 7shifts only for restaurants?$q$, $q$7shifts is purpose-built for the restaurant and food service industry, with terminology and features like tip pooling and per-shift labor cost tracking tailored to that vertical. It's less suited to businesses outside food service.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Does 7shifts handle payroll?$q$, $q$7shifts primarily focuses on scheduling and time tracking, but it offers payroll integrations and, in some markets, a payroll add-on. Businesses wanting a full standalone payroll or HR system may still need a separate dedicated provider.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Is there a mobile app for staff?$q$, $q$Yes, 7shifts has native iOS and Android apps that employees use to view schedules, request time off, message coworkers, and clock in and out. Managers can also use the mobile app, though schedule building is typically done from the web dashboard.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Independent Single-Location Restaurant$q$, $q$An owner-operator replaces spreadsheet scheduling with a simple digital schedule and time clock for a small staff.$q$, $q$Independent restaurant and cafe owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Multi-Location Restaurant Group$q$, $q$Operators standardize scheduling and compare labor cost performance across several locations from one dashboard.$q$, $q$Multi-unit restaurant groups and franchisees$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Predictive Scheduling Compliance$q$, $q$Restaurants in jurisdictions with fair workweek laws use compliance alerts to reduce risk of scheduling violations.$q$, $q$Operators in regulated US cities/states$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Tip Pooling & Shift Communication$q$, $q$Bars and full-service restaurants use built-in tip pooling and team messaging to manage front-of-house coordination.$q$, $q$Bars and full-service restaurant staff$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Free$q$, $q$Free$q$, NULL, $q$["Single location","Basic scheduling","Time clock","Team messaging"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Entrée$q$, $q$Starting around $30/month per location$q$, $q$monthly$q$, $q$["Everything in Free","Shift trading tools","Basic labor reporting","Task management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$Gourmet$q$, $q$Starting around $50/month per location$q$, $q$monthly$q$, $q$["Everything in Entrée","Labor cost forecasting","POS sales integration","Advanced reporting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$The Works$q$, $q$Custom$q$, NULL, $q$["Everything in Gourmet","Hiring and onboarding tools","Compliance features","Multi-location administration"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$7shifts is a workforce management platform built specifically for restaurants, bars, and other food service businesses. Its core function is employee scheduling, but the platform has expanded over the years into time tracking, team messaging, tip management, labor cost forecasting, and compliance tools aimed at the specific regulatory and operational pressures restaurants face.$q$, $q$The company originated in Saskatoon, Saskatchewan, Canada, and has since grown into a widely used tool across independent restaurants and multi-location restaurant groups in North America. 7shifts integrates with major restaurant point-of-sale (POS) systems, pulling in sales data so managers can build labor schedules around forecasted demand rather than guesswork. It's available as a web application for managers and as native iOS and Android apps for staff and on-the-go schedule management.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$who-7shifts-is-for$q$, $q$Who 7shifts Is For$q$, 2, ARRAY[$q$7shifts is aimed squarely at restaurant operators: independent single-location restaurants, cafes, and bars that need a simple way to build schedules and track hours, as well as multi-unit restaurant groups and chains that need consistency and labor cost visibility across locations. General managers and shift leads are the primary day-to-day users, building schedules and approving time-off requests.$q$, $q$It's also relevant to operators dealing with predictive scheduling ('fair workweek') regulations in certain US cities and states, since 7shifts includes compliance-oriented alerts and rules. Restaurants that already use a supported POS system get the most value, since sales-data integration powers the labor forecasting and reporting features that differentiate 7shifts from a generic scheduling tool.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Businesses outside food service — retail, healthcare, warehousing, and similar hourly-workforce industries — are generally better served by more general-purpose workforce management tools, since 7shifts' features, terminology, and reporting are built around restaurant operations like tip pooling and per-location sales-to-labor ratios. Companies needing a full human resources information system (HRIS) as their system of record for benefits administration, compliance filings, and multi-country payroll will likely find 7shifts' HR and payroll capabilities thinner than dedicated HR platforms, even where integrations exist.$q$, $q$Very small operations with only an owner-operator and no scheduled staff have little use for the platform, and restaurants without a supported POS integration lose some of the labor-forecasting value that justifies the cost of paid tiers. Operators looking for a single vendor to handle scheduling, full-service payroll, and benefits in one unified product may prefer an all-in-one restaurant management suite instead.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, 7shifts offers a drag-and-drop schedule builder that lets managers create, copy, and adjust weekly schedules, with employees able to view shifts, request time off, and pick up or swap shifts from the mobile app. A built-in time clock supports clock-in/clock-out via tablet, POS terminal, or mobile device, which feeds into timesheets and payroll exports.$q$, $q$Beyond scheduling, the platform includes team messaging for shift-level communication, a digital manager log book for shift notes and task handoffs, and tip pooling tools to calculate and distribute tips based on house rules. Labor cost forecasting compares scheduled labor against sales data (when integrated with a supported POS) to help managers hit target labor-cost percentages, while compliance features flag overtime risk and help with predictive scheduling law requirements in jurisdictions that have them. Hiring and onboarding tools, plus payroll integrations and reporting dashboards, round out the higher-tier plans.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dab2599f-b02e-47f7-922b-5899a8b3d1c1', $q$the-7shifts-experience$q$, $q$The 7shifts Experience$q$, 2, ARRAY[$q$Day to day, a manager typically builds the week's schedule from the web dashboard, using sales forecasts and labor-cost targets as a guide, then publishes it so staff are notified through the mobile app. Employees interact almost entirely through the app: viewing upcoming shifts, requesting availability changes, messaging coworkers about swaps, and clocking in and out.$q$, $q$The overall experience is oriented around speed and mobile convenience rather than deep configurability — schedules that used to take hours on spreadsheets can be built and adjusted in minutes, and most staff-facing interactions happen on a phone rather than a desktop. Reporting and forecasting tools are most useful to multi-location operators who need to compare labor performance across sites, while single-location owners tend to rely mainly on the core scheduling and time-clock functions.$q$]::text[], 4);
