INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Cloud VoIP Phone System$q$, $q$Hosted business phone service with extensions, call routing, and voicemail, replacing on-premise PBX hardware.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Video Conferencing$q$, $q$8x8 Meet provides video meetings with screen sharing, recording, and calendar integration alongside the phone system.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Team Chat and Messaging$q$, $q$Built-in messaging for one-to-one and group conversations within the same app used for calling and meetings.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Omnichannel Contact Center$q$, $q$8x8 Contact Center routes voice, chat, email, and social messages to agents with unified queuing and reporting.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Auto Attendant and IVR$q$, $q$Configurable call menus and interactive voice response flows to direct callers without a live receptionist.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Call Recording and Compliance$q$, $q$Recording, retention, and e-discovery tools aimed at regulated industries and quality monitoring needs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Analytics and Supervisor Dashboards$q$, $q$Real-time and historical reporting on call volumes, agent performance, and service levels.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$CRM and Business App Integrations$q$, $q$Prebuilt connectors and APIs for tools like Salesforce, Microsoft 365, and Google Workspace.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Global Voice Network$q$, $q$8x8-operated carrier infrastructure supporting international calling and multi-country deployments.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Mobile Apps$q$, $q$iOS and Android apps for calling, chat, and joining meetings away from the desk.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Combines phone, video, chat, and contact center under one vendor$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Own global voice network supports multi-country businesses$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Contact center and unified communications share the same admin platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Broad integration options with common CRM and productivity tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Long operating history in business communications compared to newer entrants$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Full pricing for higher tiers and contact center requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$More platform than very small teams or solo users typically need$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Migrating an existing phone system and number porting takes setup time$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Some users report a learning curve in the admin console for advanced configuration$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Feature parity and pricing can vary across the multiple plan tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$What is 8x8 used for?$q$, $q$8x8 is used as a business phone system, video conferencing tool, and team chat platform, and can be extended with a contact center module for customer support and sales teams. It's typically deployed as a replacement for a traditional on-premise PBX and separate collaboration apps.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Does 8x8 offer a free trial?$q$, $q$8x8 has offered free trials for parts of its platform, such as video meetings and certain phone plans, though availability and length can vary by product and region. Prospective business customers should check current trial terms directly on 8x8's website or with a sales representative.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Is 8x8 just a phone system, or does it include a contact center?$q$, $q$8x8 offers both: a unified communications suite (phone, video, chat) sold as 8x8 Work and 8x8 Meet, and a separate but integrated contact center product, 8x8 Contact Center. Businesses can start with just the phone and collaboration tools and add contact center capabilities later.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$What integrations does 8x8 support?$q$, $q$8x8 integrates with widely used business tools including Salesforce, Microsoft 365, Microsoft Teams, and Google Workspace, along with APIs for custom integrations. The exact set of available integrations can depend on the specific plan and product being used.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$How does 8x8 pricing work?$q$, $q$8x8 prices its unified communications plans per user per month, with published starting rates for entry-level tiers and higher tiers unlocking more features like advanced analytics or larger meeting sizes. Contact center pricing is generally handled through a custom quote based on agent count and required features.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Replacing a legacy office phone system$q$, $q$Businesses moving off an aging on-premise PBX can migrate extensions and call routing to 8x8's cloud phone service.$q$, $q$Small to mid-sized businesses with an outdated phone system$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Supporting a distributed or remote workforce$q$, $q$Teams spread across locations use 8x8's phone, video, and chat apps to stay connected without a physical office phone system.$q$, $q$Remote and hybrid teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Running a customer support or sales contact center$q$, $q$Support and sales teams use 8x8 Contact Center to route calls, chats, and emails to agents with supervisor reporting.$q$, $q$Customer support and inside sales teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Consolidating multi-location or international offices$q$, $q$Organizations with offices in multiple countries use 8x8's global voice network to standardize calling under one platform.$q$, $q$Multi-location and international businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Express$q$, $q$$15/month$q$, $q$monthly$q$, $q$["Basic cloud phone for small teams","Unlimited calling in supported regions","Simple setup with limited admin controls"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$X2$q$, $q$~$24/user/month$q$, $q$monthly$q$, $q$["Unified voice, video, and chat","Voicemail and call routing","Integrations with common business apps"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$X4$q$, $q$~$44/user/month$q$, $q$monthly$q$, $q$["Advanced call handling and analytics","Larger video meeting capacity","Priority support options"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$Contact Center / X6-X8$q$, $q$Custom$q$, NULL, $q$["Omnichannel routing for voice, chat, and email","Workforce and quality management","Custom quote based on agent count and needs"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$8x8 is a publicly traded cloud communications company (Nasdaq: EGHT) that provides a unified platform covering business VoIP phone service, video conferencing, team messaging, and contact center software. Rather than selling these as separate point products, 8x8 packages them under what it calls the 8x8 XCaaS (Experience Communications as a Service) platform, aimed at replacing legacy on-premise PBX hardware and disconnected collaboration tools.$q$, $q$The company has been operating in the communications space since the late 1980s and moved into hosted VoIP and unified communications in the 2000s, giving it a longer track record than many newer cloud-communications entrants. Core products include 8x8 Work (cloud phone system), 8x8 Meet (video conferencing), and 8x8 Contact Center, sold individually or bundled for organizations that want a single vendor for both internal collaboration and customer-facing support.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$who-8x8-is-for$q$, $q$Who 8x8 Is For$q$, 2, ARRAY[$q$8x8 is best suited to small and mid-sized businesses that want to consolidate phone, video, and messaging under one vendor and one bill, rather than stitching together separate tools for calling, meetings, and chat. It also targets larger organizations and multi-location businesses that need a reliable, carrier-grade phone system with international calling reach, since 8x8 operates its own global voice network in many regions.$q$, $q$Companies running or scaling a customer support or sales team are a strong fit too, since 8x8 Contact Center can be layered on top of the same platform used for internal communications, giving supervisors unified reporting across both employee and customer interactions. IT teams that want centralized admin controls, compliance features, and integrations with tools like Microsoft Teams or Salesforce also tend to find the platform's enterprise-oriented feature set useful.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo freelancers, very small teams, or anyone just looking for a simple, cheap softphone app may find 8x8 more platform than they need, both in terms of features and in the way pricing scales with add-ons like contact center seats. Businesses that want fully transparent, self-serve pricing for every tier may also be frustrated, since higher-tier and contact center plans typically require a conversation with sales rather than an instant online quote.$q$, $q$Teams that are already deeply invested in another ecosystem's calling feature (for example, using Microsoft Teams Phone or Zoom Phone as the primary dial tone) may not see enough incremental benefit to justify switching, since 8x8 works best when it's the primary communications backbone rather than a secondary tool. Organizations with very limited IT support may also want to weigh the setup and porting work involved in migrating an existing phone system.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, 8x8 provides a cloud PBX and business VoIP phone system with standard features such as auto attendants, call routing, voicemail-to-email, and call recording, alongside video conferencing (8x8 Meet) and team chat for internal collaboration. These pieces are designed to work as one product rather than bolted-together acquisitions, so users typically move between calling, chat, and video from a single desktop or mobile app.$q$, $q$On the customer-facing side, 8x8 Contact Center adds omnichannel routing (voice, chat, email, and social channels), interactive voice response (IVR), workforce and quality management tools, and analytics dashboards for supervisors. The platform also offers APIs and prebuilt integrations with common business software, including CRM systems like Salesforce and productivity suites like Microsoft 365 and Google Workspace, along with compliance-oriented features (call recording retention, e-discovery, and security certifications) aimed at regulated industries.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', $q$the-8x8-experience$q$, $q$The 8x8 Experience$q$, 2, ARRAY[$q$Day to day, most users interact with 8x8 through a desktop app or web client that combines a phone dialer, chat, and meeting scheduler in one interface, plus mobile apps for iOS and Android for calling and messaging on the go. Because the underlying network is run by 8x8 itself in many regions rather than relying purely on third-party carriers, call quality and uptime are generally reported as solid, which matters for businesses that treat their phone system as mission-critical infrastructure.$q$, $q$Setup for a straightforward phone and video rollout is relatively quick, though larger deployments involving number porting, contact center configuration, or integration with existing CRM and helpdesk tools benefit from working with 8x8's implementation team. Admins get a centralized management console for provisioning users, setting call routing rules, and pulling usage or quality-of-service reports, which is where the platform's enterprise communications heritage shows most clearly.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d833b94c-8537-403d-b648-3070a9fce206', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
