INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Full-image and file backup$q$, $q$Backs up entire disks or individual files and folders on a customizable schedule.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Anti-ransomware protection$q$, $q$Uses behavioral detection to identify and can automatically roll back files affected by ransomware attacks.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Anti-malware scanning$q$, $q$Combines signature-based and behavior-based malware detection in the same agent as backup.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Vulnerability assessments$q$, $q$Scans protected systems for known software vulnerabilities that need patching.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Patch management$q$, $q$Applies operating system and third-party application patches from the same console (business/MSP editions).$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Cloud and hybrid storage$q$, $q$Stores backups locally, on network storage, or in Acronis' own cloud storage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Bare-metal and dissimilar hardware recovery$q$, $q$Restores a full system image to different physical or virtual hardware.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Microsoft 365 and Google Workspace backup$q$, $q$Protects cloud productivity suite data such as mail, files, and shared drives.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Multi-tenant management console$q$, $q$Lets MSPs manage backup and security policies across many client organizations from one dashboard.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$File notarization$q$, $q$Uses blockchain-based hashing to help verify that a backed-up file hasn't been tampered with.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Combines backup and cybersecurity in a single agent and console$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Strong, long-established reputation for image-based disk recovery$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Ransomware detection with automatic file rollback$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Scales from single home devices to multi-tenant MSP deployments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Flexible storage options, including local, network, and Acronis cloud$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Business and MSP pricing is quote-based and not fully transparent upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Bundled security suite may be less feature-rich than dedicated best-of-breed EDR tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Agent can be resource-intensive on lower-spec machines$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Learning curve for the full range of console options in business editions$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Not open-source or self-hostable, which limits appeal for that niche$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$What is Acronis Cyber Protect?$q$, $q$It's a data protection platform from Acronis that combines backup and disaster recovery with anti-malware, anti-ransomware, and endpoint management in one agent. It's offered in consumer (Home Office), business, and MSP-focused (Cyber Protect Cloud) editions.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Is there a free trial?$q$, $q$Yes, Acronis typically offers a free trial period for its Cyber Protect products so prospective customers can test backup and security features before purchasing. Trial length and terms can vary by edition and region, so it's worth checking current terms on acronis.com.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Does Acronis Cyber Protect replace a standalone antivirus?$q$, $q$For many small businesses and individuals, its bundled anti-malware and anti-ransomware engine is designed to serve as the primary endpoint protection alongside backup. Larger organizations with existing enterprise security stacks may choose to run it primarily for backup while keeping a separate dedicated security product.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$What platforms does it support?$q$, $q$Acronis Cyber Protect supports Windows and Mac desktops and laptops, along with physical and virtual servers, and integrates with cloud workloads like Microsoft 365 and Google Workspace. Mobile apps are also available for accessing and managing backups from Android and iOS devices.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$How is Acronis Cyber Protect priced?$q$, $q$Consumer Home Office plans are sold as an annual subscription per device, typically in the tens of dollars per year. Business and MSP editions are priced per protected workload and generally require a quote from Acronis or an authorized partner.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Consolidating backup and antivirus for a small business$q$, $q$Replace separate backup software and antivirus licenses with a single agent that covers both, reducing the number of vendors and dashboards IT staff manage.$q$, $q$Small business owners and IT generalists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$MSP service delivery across many clients$q$, $q$Manage backup, patching, and security policies for dozens or hundreds of client organizations from one multi-tenant console with per-client billing.$q$, $q$Managed service providers (MSPs)$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Ransomware recovery planning$q$, $q$Combine behavioral ransomware detection with automatic file rollback and image-based recovery to reduce downtime if an attack succeeds.$q$, $q$IT administrators responsible for business continuity$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Home and small-office device protection$q$, $q$Protect a handful of personal or small-office computers with scheduled full-disk backups and built-in anti-malware in one subscription.$q$, $q$Individuals and very small offices$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Cyber Protect Home Office$q$, $q$$50-70/year$q$, $q$monthly$q$, $q$["Full-image and file backup for 1+ devices","Anti-ransomware and anti-malware protection","Cloud storage option","Mobile backup via Android/iOS apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Cyber Protect Standard$q$, $q$Custom$q$, NULL, $q$["Backup and recovery for servers and workstations","Anti-malware protection","Vulnerability assessments","Central management console"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Cyber Protect Advanced$q$, $q$Custom$q$, NULL, $q$["Everything in Standard","Patch management","Advanced anti-ransomware and forensic tools","Extended workload support (VMs, cloud apps)"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$Cyber Protect Cloud (for MSPs)$q$, $q$Custom$q$, NULL, $q$["Multi-tenant management console","Per-client billing and white-labeling","Backup plus security bundled per workload","RMM and patch management add-ons"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Acronis Cyber Protect is a unified data protection platform from Acronis, a company that built its early reputation on disk imaging and backup software before expanding into cybersecurity. The product merges backup and recovery with anti-malware, anti-ransomware, and vulnerability management into a single agent and console, rather than requiring separate tools for each function.$q$, $q$It ships in different forms depending on the audience: Acronis Cyber Protect Home Office for individuals and small offices, and Acronis Cyber Protect (Standard/Advanced editions) plus Acronis Cyber Protect Cloud for businesses and the managed service providers (MSPs) who resell it. The core idea across all editions is the same — protect a device or workload with one agent that handles both data recovery and threat prevention, reducing the coordination overhead of running a backup tool and an antivirus tool side by side.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$who-acronis-cyber-protect-is-for$q$, $q$Who Acronis Cyber Protect Is For$q$, 2, ARRAY[$q$The platform is well suited to IT teams and MSPs who want to consolidate backup, disaster recovery, and endpoint security under one vendor and one console, rather than stitching together separate backup software and a standalone antivirus product. Small and mid-sized businesses without a dedicated security team often benefit from this consolidation because it reduces the number of dashboards and agents that need to be monitored.$q$, $q$It also appeals to consumers and prosumers who want a single subscription that covers full-disk imaging, file sync, and ransomware protection for a handful of home or small-office computers. MSPs in particular are a core audience: Acronis Cyber Protect Cloud is built around multi-tenant management, per-client billing, and white-labeling, which fits how managed service providers deliver protection to many end customers at once.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that already have a mature, best-of-breed EDR/XDR stack (for example Microsoft Defender for Endpoint or CrowdStrike) alongside a separate enterprise backup solution may find little reason to replatform onto Acronis, since ripping out established security tooling carries its own risk and retraining cost. Teams with highly specialized backup needs — very large-scale database backup, complex enterprise storage arrays, or deep integration with a specific hypervisor ecosystem — may also find more mature, narrowly focused vendors a better fit.$q$, $q$Very small budget-conscious users who only need basic file backup, with no interest in anti-malware bundling, may find dedicated backup-only tools simpler and cheaper. Buyers who need fully open, self-hosted, or open-source software should also look elsewhere, since Acronis Cyber Protect is a commercial, closed-source product.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Acronis Cyber Protect provides full-image and file-level backup with flexible scheduling, retention rules, and recovery to dissimilar hardware or virtual machines. Backups can be stored locally, on network storage, or in Acronis' own cloud storage, and the platform supports physical servers, virtual machines, and common workloads such as Microsoft 365 and Google Workspace data.$q$, $q$Layered on top of backup is a security stack that includes signature-based and behavioral anti-malware detection, anti-ransomware protection that can automatically roll back files encrypted by an attack, vulnerability assessments, and patch management for common operating systems and applications. Acronis markets its anti-ransomware engine as using AI-driven behavioral heuristics to catch threats that pure signature scanning would miss, in addition to traditional detection methods.$q$, $q$For business and MSP editions, the platform adds remote monitoring and management (RMM) capabilities, a management console for handling many endpoints or client tenants at once, and reporting aimed at demonstrating compliance and protection status to stakeholders. A notarization feature using blockchain-based hashing is also part of the platform's file-authenticity claims, letting users verify a file hasn't been altered since it was backed up.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e09c036b-bf39-4a03-9832-b843bd6525c7', $q$the-acronis-cyber-protect-experience$q$, $q$The Acronis Cyber Protect Experience$q$, 2, ARRAY[$q$Setup generally involves installing a single agent on each protected device, then configuring backup and protection plans from a central web-based console. Day-to-day, most users interact with the product passively — backups run on schedule and the security engine monitors in the background — with the console used mainly to review status, alerts, and periodic reports.$q$, $q$Recovery is the moment the platform is judged most heavily, and Acronis has built its reputation over two decades around dependable image-based restore, including bare-metal recovery to different hardware. For MSPs, the day-to-day experience centers on the multi-tenant admin console, where technicians manage protection plans and billing across many client organizations from one place rather than juggling separate tools per client.$q$]::text[], 4);
