INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Self-Service Booking Page$q$, $q$A public, shareable page where clients can view real-time availability and book appointments themselves.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Calendar Sync$q$, $q$Two-way syncing with Google Calendar, Outlook, and iCloud to prevent double-bookings.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Automated Reminders$q$, $q$Email and, on higher plans, text reminders sent automatically to reduce no-shows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Online Payments$q$, $q$Built-in payment collection at the time of booking through integrations like Stripe, PayPal, and Square.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Custom Intake Forms$q$, $q$Configurable forms and questionnaires clients complete during the booking process.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Time Zone Detection$q$, $q$Automatically displays appointment times in the client's local time zone.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Packages and Memberships$q$, $q$Ability to sell bundled sessions, packages, or recurring memberships to clients.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Group Class Scheduling$q$, $q$Support for scheduling group classes or workshops with multiple attendees per slot.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Multi-Staff and Location Support$q$, $q$Manage multiple calendars, staff members, and business locations from one account on higher-tier plans.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$API and Integrations$q$, $q$An API and third-party integrations, including Zoom and Squarespace websites, for extending scheduling into other tools.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Simple, uncluttered self-booking page for clients$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Straightforward setup for solo practitioners and small teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Tight integration with Squarespace websites$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Built-in payment collection at time of booking$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Automated reminders help reduce no-shows$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$No permanent free plan, only a free trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Advanced features like HIPAA compliance and higher staff limits require pricier tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Not a full CRM or marketing automation platform$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Customization options can feel limited for complex, non-standard booking workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Per-staff and per-location limits may require upgrading as a business grows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Is Acuity Scheduling the same as Squarespace Scheduling?$q$, $q$Acuity Scheduling was acquired by Squarespace in 2019 and continues to be sold under its own name while being integrated with Squarespace's broader product lineup. Squarespace has also referred to scheduling functionality under its own branding in some contexts, but Acuity Scheduling remains the primary standalone product.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Does Acuity Scheduling have a free plan?$q$, $q$Acuity Scheduling does not offer an ongoing free tier; instead, it provides a free trial period so businesses can test the platform before committing to a paid plan. After the trial, continued use requires one of its paid subscription tiers.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Can clients book appointments without creating an account?$q$, $q$Yes, clients typically book directly from a business's public scheduling page by selecting a time and entering their details, without needing to create their own Acuity account. This self-service flow is one of the platform's core features.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Does Acuity Scheduling support online payments?$q$, $q$Yes, Acuity integrates with payment processors such as Stripe, PayPal, and Square so businesses can collect payment at the time of booking. This is available across its plans, with deeper payment features like packages and memberships unlocked on higher tiers.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Is Acuity Scheduling suitable for healthcare providers?$q$, $q$Acuity offers a HIPAA-compliant configuration on its top-tier plan, which is intended for healthcare or wellness providers with those compliance needs. Businesses should confirm current compliance details directly with Acuity before relying on it for regulated healthcare use.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Solo practitioner booking$q$, $q$A therapist, coach, or consultant sets up a personal scheduling page so clients can book sessions directly without email back-and-forth.$q$, $q$Independent service providers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Salon and wellness appointments$q$, $q$A salon or wellness studio manages staff calendars, client intake forms, and appointment payments in one system.$q$, $q$Salons, spas, and wellness businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Group classes and workshops$q$, $q$A fitness instructor or educator schedules recurring group classes with capacity limits and automated reminders.$q$, $q$Fitness instructors and class-based educators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Multi-location team scheduling$q$, $q$A business with several locations or staff members coordinates calendars and availability across the team from a single account.$q$, $q$Small businesses with multiple staff or locations$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Emerging$q$, $q$$16/month$q$, $q$monthly$q$, $q$["Core online booking page","Payment acceptance","Calendar integrations","1 staff calendar"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Growing$q$, $q$$27/month$q$, $q$monthly$q$, $q$["Everything in Emerging","Text appointment reminders","Packages and memberships","Up to 6 staff calendars or locations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$Powerhouse$q$, $q$$49/month$q$, $q$monthly$q$, $q$["Everything in Growing","HIPAA-compliant configuration","Multiple time zone support","Up to 36 staff calendars or locations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Acuity Scheduling is an online appointment scheduling platform that lets businesses accept bookings, collect payments, and manage calendars from a single, client-facing scheduling page. It was founded in 2006 by Gavin Zuchlinski, who built the tool to help his mother, a massage therapist, automate her own booking process, and it grew into one of the more widely used scheduling tools for service-based businesses.$q$, $q$In 2019, Acuity Scheduling was acquired by Squarespace, marking Squarespace's first acquisition. It continues to operate as a standalone product and brand under the Acuity Scheduling name, while also being sold and integrated as part of the broader Squarespace ecosystem, including tighter ties with Squarespace websites and Squarespace's other business tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$who-acuity-scheduling-is-for$q$, $q$Who Acuity Scheduling Is For$q$, 2, ARRAY[$q$Acuity Scheduling is aimed at solo practitioners and small teams that run appointment-based businesses, such as coaches, consultants, therapists, tutors, salons, and healthcare or wellness providers. Its core value proposition is letting clients self-book directly from a public scheduling page without back-and-forth emails, while the business owner manages availability, intake forms, and payments in one place.$q$, $q$It also suits businesses that already use, or plan to use, a Squarespace website, since the two products integrate closely. Multi-location businesses and teams with several staff members can use the higher-tier plans to manage multiple calendars, locations, and time zones from a single account.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Acuity Scheduling is not built as a general-purpose CRM, marketing automation, or point-of-sale system, so businesses looking for deep customer relationship management, inventory tracking, or in-depth marketing campaigns will likely need to pair it with, or choose, other software. Very large enterprises with complex staffing, franchise, or resource-scheduling needs may find its plan tiers and staff limits restrictive compared to enterprise-grade scheduling suites.$q$, $q$Businesses that want a permanent free plan should also look elsewhere, since Acuity offers a free trial rather than an ongoing free tier. Teams that need heavy customization of the booking workflow beyond what Acuity's settings expose may find more flexibility with a developer-first or fully custom-built solution.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Acuity Scheduling provides a customizable public booking page where clients can see real-time availability and self-schedule appointments, classes, or packages. It syncs with calendars such as Google Calendar, Outlook, and iCloud to avoid double-booking, and it automatically detects and adjusts for the client's time zone.$q$, $q$Beyond basic booking, Acuity supports automated email and text appointment reminders, customizable intake and consent forms, and built-in payment collection through integrations with processors like Stripe, PayPal, and Square. Higher plans add features such as memberships and packages, group class scheduling, multiple staff calendars and locations, and HIPAA-compliant configurations for healthcare-adjacent use cases.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb973a74-57dc-44bc-837f-58dfac85e6ce', $q$the-scheduling-experience$q$, $q$The Scheduling Experience$q$, 2, ARRAY[$q$From the client's perspective, booking with Acuity typically involves visiting a business's scheduling link, selecting an appointment type and available time slot, filling out any required intake form, and confirming with payment if required. The interface is intentionally simple, aiming to reduce the number of steps between finding an open slot and confirming a booking.$q$, $q$From the business owner's side, the admin dashboard centralizes appointment management, client records, and payment history, with settings to control buffer times, cancellation policies, and availability windows. The scheduling page itself can be embedded on a website, linked from social media or email, or connected directly into a Squarespace site, which is one of the more common ways businesses distribute their booking link.$q$]::text[], 4);
