INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed8ef4d3-923b-43df-8e5d-e18829ae9f91', $q$Action-Based Logic$q$, $q$Define app behavior, like navigation and data updates, through configurable action flows.$q$, 4);
