INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ed8ef4d3-923b-43df-8e5d-e18829ae9f91', $q$Real-Time Preview$q$, $q$View how the app looks and functions as changes are made during building.$q$, 8);
