INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('951b342f-ef42-4fc5-afdd-6e5a7df3ad94', $q$Automated Reporting$q$, $q$Generate exportable performance reports for internal review or client presentations.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('951b342f-ef42-4fc5-afdd-6e5a7df3ad94', $q$Multi-Account & Team Access$q$, $q$Manage multiple ad accounts and collaborate with team members or clients from one workspace.$q$, 8);
