INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Generative Recolor$q$, $q$Automatically recolors existing vector artwork based on prompts or color themes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Generative Video$q$, $q$Generates and extends video clips, including Generative Extend in Premiere Pro.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Content Credentials$q$, $q$Attaches transparent metadata to generated assets disclosing AI involvement.$q$, 7);
