INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Trained on licensed and public domain content for commercial safety$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Deeply integrated into Photoshop, Illustrator, Express, and Premiere Pro$q$, 1);
