INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Photorealism and stylistic range can lag behind specialist AI image tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Full value depends on buying into the Adobe/Creative Cloud ecosystem$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Video generation features are newer and more limited than image tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Credit-based pricing can be harder to predict than flat subscriptions$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Is Adobe Firefly free to use?$q$, $q$Yes, Firefly offers a free plan that includes a limited number of monthly generative credits and access to core tools. Paid plans add higher credit allowances, additional features, and higher-resolution outputs.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$How is Firefly different from Midjourney or Stable Diffusion?$q$, $q$Firefly is trained on Adobe Stock images, openly licensed content, and public domain material rather than broadly scraped web data. Adobe markets this as making Firefly output more commercially safe, and backs eligible enterprise plans with IP indemnification.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Can I use Firefly-generated content commercially?$q$, $q$Adobe designed Firefly's training data and licensing to support commercial use, and enterprise customers on eligible plans receive IP indemnification. Users should still review Adobe's current terms of use for their specific plan before commercial deployment.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Do I need Photoshop or Illustrator to use Firefly?$q$, $q$No, Firefly is also available as a standalone web application at firefly.adobe.com. It's additionally embedded as generative features inside Creative Cloud apps like Photoshop, Illustrator, Express, and Premiere Pro.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$What are Firefly's generative credits?$q$, $q$Generative credits are the usage unit that meters how many generations a user can create each month. Free and paid plans each include a set credit allowance, and higher-tier plans provide larger monthly allotments.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Marketing asset production$q$, $q$Quickly generate on-brand images, backgrounds, and text effects for campaigns and social posts.$q$, $q$Marketing and social media teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Design concepting and ideation$q$, $q$Explore visual directions and mood boards rapidly before committing to full production artwork.$q$, $q$Graphic and brand designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Product imagery and compositing$q$, $q$Generate or extend backgrounds and scenes around product photography for e-commerce listings.$q$, $q$E-commerce and retail teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Video editing extensions$q$, $q$Use Generative Extend to lengthen or smooth video clips without reshooting footage.$q$, $q$Video editors and content creators$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Free$q$, $q$Free$q$, $q$monthly$q$, $q$["Limited monthly generative credits","Access to core text-to-image and design tools","Standalone web app access","Content Credentials on generated assets"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Firefly Standard$q$, $q$Around $10/month$q$, $q$monthly$q$, $q$["Higher monthly generative credit allowance","Access to additional generation features","Standalone app and select app integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Firefly Pro$q$, $q$Around $30/month$q$, $q$monthly$q$, $q$["Larger generative credit allowance","Access to video generation features","Higher-resolution outputs","Priority access to new generative tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Custom generative credit volumes","IP indemnification","API access for custom integrations","Admin and governance controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Adobe Firefly is Adobe's family of generative AI models covering image, vector, and design generation, first introduced in 2023 and since expanded into video and audio generation. Rather than a single tool, Firefly is best understood as an underlying model family that powers generative features across Photoshop, Illustrator, Premiere Pro, and Adobe Express, while also existing as a standalone web application at firefly.adobe.com.$q$, $q$The defining characteristic of Firefly, and a point Adobe emphasizes heavily in its marketing, is that the models are trained on Adobe Stock images, openly licensed content, and public domain material rather than content scraped indiscriminately from the open web. This is positioned as a meaningful differentiator against generative tools like Midjourney or Stable Diffusion, which have faced ongoing scrutiny over training data provenance, and it underpins Adobe's claim that Firefly output is designed to be commercially safe for business use.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$who-firefly-is-for$q$, $q$Who Firefly Is For$q$, 2, ARRAY[$q$Firefly is aimed at creative professionals, marketing teams, and agencies who are already working inside the Adobe ecosystem and want generative capabilities layered directly into tools they use daily, such as Generative Fill in Photoshop or Text to Vector in Illustrator. It suits teams producing high volumes of marketing assets, social content, or product imagery who need speed without leaving their existing production pipeline.$q$, $q$It is also well suited to organizations that are cautious about copyright and IP exposure when adopting generative AI. Because Firefly's training data is licensed or public domain, and because Adobe offers IP indemnification to enterprise customers on eligible plans, legal and compliance-conscious businesses often find it an easier sell internally than tools trained on unclear data sources.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Users chasing the most photorealistic results or the broadest stylistic range, particularly for artistic or highly stylized imagery, may find Firefly's outputs comparatively conservative next to specialist generative image tools. Adobe's models are tuned partly for commercial safety and brand-friendly output, which can mean less creative unpredictability than competitors optimized purely for visual impressiveness.$q$, $q$Firefly is also less appealing to independent creators or hobbyists who don't want a subscription or credit-based system, or who prefer self-hosted, open-weight models they can run and fine-tune locally, such as Stable Diffusion. Anyone without an existing Creative Cloud workflow may not get full value from Firefly's deepest integrations, which are built around Adobe's own applications.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Firefly's core capabilities include text-to-image generation, Generative Fill and Generative Expand for adding, removing, or extending image content in Photoshop, and Text Effects for applying generative styling to typography. On the vector side, Firefly powers Text to Vector Graphic and Generative Recolor inside Illustrator, letting designers generate and restyle vector artwork from prompts.$q$, $q$More recently, Firefly has extended into video with generative video tools such as Generative Extend in Premiere Pro, which lengthens clips using AI-generated frames. Every generation is tagged with Content Credentials, Adobe's metadata standard for disclosing AI involvement, and usage is metered through a generative credits system that applies across the free and paid tiers.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', $q$generative-design-experience$q$, $q$The Generative Design Experience$q$, 2, ARRAY[$q$The standalone Firefly web app provides a prompt-driven interface where users can generate images, apply style presets, upload reference images to guide composition or color, and browse templates for common design formats. It's designed to be approachable for non-designers while still offering enough controls, such as aspect ratio, style strength, and content type, for more deliberate creative direction.$q$, $q$For deeper workflows, Firefly-generated assets flow directly into Adobe's broader Creative Cloud suite for refinement, and Adobe also offers a Firefly API for enterprises that want to embed generation programmatically into their own applications or marketing pipelines. This combination of a simple standalone entry point, deep in-app integration, and an API for custom builds is central to how Adobe positions Firefly against more narrowly scoped generative tools.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('634ed19f-2d5a-4498-ac78-c41f58bbdf9a', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
