INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Pen Tool & Bezier Paths$q$, $q$Draw precise, editable vector shapes using anchor points and curve handles.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Advanced Typography$q$, $q$Detailed character and paragraph controls with OpenType font support for logotypes and lettering.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Multiple Artboards$q$, $q$Design several layouts or size variants within a single file.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Image Trace$q$, $q$Convert raster images and sketches into editable vector artwork automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Generative Recolor$q$, $q$Use Adobe Firefly-powered AI to generate new color variations for existing artwork.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Illustrator for iPad$q$, $q$A dedicated touch-optimized app for sketching and vector editing on iPad.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Creative Cloud Libraries$q$, $q$Share colors, styles, and graphic assets across Illustrator and other Adobe apps.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Pattern & Gradient Tools$q$, $q$Build repeatable patterns and complex multi-stop gradients directly on vector shapes.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Print-Ready Color Management$q$, $q$Work in CMYK, apply Pantone spot colors, and export files with bleed and trim marks.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Industry-standard file compatibility (AI, EPS, PDF, SVG)$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Infinitely scalable vector output with no quality loss$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Best-in-class typography and pen tool precision$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Deep integration with Photoshop and other Creative Cloud apps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Strong print production and color management tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Steep learning curve for new users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Subscription-only pricing, no perpetual license option$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Requires periodic online license verification$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Can slow down with very complex, layer-heavy files$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Overkill for simple, quick social media graphics$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Is Adobe Illustrator free?$q$, $q$No, Illustrator is a paid, subscription-based application with no permanent free tier. Adobe typically offers a limited-time free trial so new users can test it before committing to a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$What's the difference between Illustrator and Photoshop?$q$, $q$Illustrator is a vector editor, building artwork from scalable paths ideal for logos, icons, and typography. Photoshop is a raster (pixel-based) editor built for photo editing, retouching, and image compositing.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$How is Illustrator different from Canva?$q$, $q$Illustrator gives designers precise, path-based control for building original artwork from scratch, while Canva is a template-first tool optimized for speed and ease of use. Canva has a much gentler learning curve but less precision and flexibility for professional vector design.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Can I use Illustrator on an iPad?$q$, $q$Yes, Adobe offers a dedicated Illustrator for iPad app with a touch-optimized interface for sketching and vector editing. Files sync with the desktop version through Creative Cloud.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$What file formats does Illustrator support?$q$, $q$Illustrator natively works in AI (its own format) and readily exports to EPS, PDF, SVG, PNG, and JPG, among others. This broad compatibility is a major reason it's used as a standard hand-off format between designers and print or web production teams.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Logo & Brand Identity Design$q$, $q$Create scalable logos and full brand identity systems that need to work across sizes from favicons to signage.$q$, $q$Brand and identity designers, design agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Icon & UI Asset Creation$q$, $q$Build clean, crisp icon sets and interface graphics that scale sharply across screen densities.$q$, $q$Product designers, UI/UX teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Print Production & Packaging$q$, $q$Design packaging, posters, and print materials with precise CMYK color control, bleed, and trim marks.$q$, $q$Print designers, packaging studios$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Editorial & Technical Illustration$q$, $q$Produce detailed illustrations, infographics, and technical diagrams that require fine vector control.$q$, $q$Illustrators, editorial and infographic artists$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Illustrator (Single App)$q$, $q$Around $20-23/month$q$, $q$monthly$q$, $q$["Full Illustrator desktop app","100GB cloud storage","Illustrator for iPad included","Adobe Fonts access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Creative Cloud All Apps$q$, $q$Around $55-60/month$q$, $q$monthly$q$, $q$["Illustrator plus Photoshop, InDesign, and other Creative Cloud apps","100GB cloud storage","Adobe Firefly generative credits","Access to Adobe Fonts and Libraries"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$Students & Teachers$q$, $q$Discounted rate, roughly $20/month (first year)$q$, $q$monthly$q$, $q$["All Creative Cloud apps at a reduced education price","Requires proof of enrollment","Same core features as All Apps plan"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Adobe Illustrator is a vector graphics editor developed by Adobe Inc. and distributed as part of the Creative Cloud subscription suite. First released for the Mac in the late 1980s, it has become the de facto standard tool for creating logos, icons, typography, packaging artwork, and illustrations across the design industry.$q$, $q$Unlike raster editors, Illustrator builds artwork from mathematically defined paths (points, lines, and curves) rather than pixels. This means shapes and text can be scaled to any size — from a business card to a billboard — without losing sharpness, which is why Illustrator remains the default choice for logo and brand identity work.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$who-illustrator-is-for$q$, $q$Who Illustrator Is For$q$, 2, ARRAY[$q$Illustrator is built for graphic designers, brand and identity designers, and illustrators who need precise control over shapes, curves, and typography. It's also widely used by packaging designers, print production artists, and UI/icon designers who need clean, scalable vector assets that hold up across formats and sizes.$q$, $q$Design students and agencies also rely on Illustrator because file compatibility (AI, EPS, PDF, SVG) and skill with the software are effectively industry expectations. Studios producing branding, editorial illustration, or technical/infographic artwork typically standardize on it for its precision and print-readiness.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Illustrator is not the right tool for photo editing or retouching — that work belongs in Photoshop, which is built around pixel-based raster images rather than vector paths. Users who mainly need to edit photographs, adjust exposure, or composite images will find Illustrator's toolset poorly suited to that task.$q$, $q$People who just need to quickly assemble social media graphics, presentations, or marketing flyers from pre-made layouts are usually better served by a template-first tool like Canva, which trades precision for speed and a much shorter learning curve. Illustrator's pen tool and bezier-based workflow have a real learning curve, so casual or occasional users without design training may find it more complex than necessary.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Core to Illustrator is the Pen tool and its bezier curve system, which lets designers draw precise anchor-point-based paths — the foundation of scalable logos and icons. Strong typography controls, including OpenType support and detailed character/paragraph formatting, make it a preferred tool for logotypes and lettering.$q$, $q$Illustrator supports multiple artboards within one file (useful for producing size variants), an Image Trace feature that converts raster images into editable vectors, and pattern and gradient tools for complex fills. Recent versions have added generative AI features, such as Generative Recolor, built on Adobe Firefly, alongside a dedicated Illustrator for iPad app and deep integration with Creative Cloud Libraries for sharing colors, styles, and assets across projects.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', $q$the-vector-editing-experience$q$, $q$The Vector Editing Experience$q$, 2, ARRAY[$q$Because every shape in Illustrator is defined by mathematical paths rather than a fixed pixel grid, artwork can be resized infinitely — from a favicon to a trade-show banner — without any loss of quality. This is the fundamental distinction from Photoshop, which works with a fixed-resolution raster canvas that degrades when scaled up.$q$, $q$That precision comes with a steeper learning curve than template-based tools like Canva: mastering anchor points, bezier handles, and the Appearance panel takes practice. In exchange, Illustrator offers production-grade features expected in professional print and brand work, including CMYK color management, Pantone spot color support, and export options for bleed, trim marks, and web-ready formats like SVG and PDF.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('53d8a955-0f74-4814-b877-caeb34bf0761', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
